import React from 'react'
import styled from 'styled-components'
import Accordion from '@material-ui/core/Accordion';
import AccordionDetails from '@material-ui/core/AccordionDetails';
import AccordionSummary from '@material-ui/core/AccordionSummary';
import Typography from '@material-ui/core/Typography';
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';
import { useState } from 'react';
import { useEffect } from 'react';
import { db } from '../../components/firebase';
import { Button } from '@material-ui/core';


const SoldProducts = React.memo(() => {
    const [items, setItems] = useState([])


    useEffect(() => {
        db.collection('cm-offers').orderBy('timestamp', 'desc').onSnapshot(snap => (
            setItems(snap.docs.map(doc => (
                {
                    id: doc.id,
                    data: doc.data()
                }
            )))
        ))
    }, [])

    const handleDelivered = (id, read) => {
        db.collection('cm-offers').doc(id).update({
            read: !read 
        })
    }

    const handleDelete = (id) => {
        if (window.confirm(`Sigur ștergi acest client?`) === true) {
            db.collection('cm-offers').doc(id).delete()
        }
    }


    return (
        <Container>
            <Title>Oferte:</Title>

            {items && items.length < 1 ? 
                <h4>Nici o ofertă</h4> : 
                items.map(({id, data}, idx) => (
                <MyAccordion  key={id} className={data.read ? 'marked' : ''}>
                    <AccordionSummary
                    expandIcon={<ExpandMoreIcon />}
                    aria-controls="panel1bh-content"
                    id="panel1bh-header"
                    >
                        <MyTypography className={data?.read ? 'marked' : ''}>{data?.name}</MyTypography>
                        <PriceTypography className={data?.read ? 'marked' : ''}><i>Suma:</i> <b>{data?.total}</b> RON</PriceTypography>
                    </AccordionSummary>
                    <AccordionDetails style={{flexDirection: 'column'}}>
                        <Typography><i>Ofertat la data:</i> <b>{new Date(data?.timestamp?.toDate()).toLocaleString('ro')}</b>
                        </Typography>
                        <Typography><i>Nume:</i> <b>{data?.name}</b></Typography>
                        <Typography><i>Telefon:</i> <b>{data?.phone}</b></Typography>
                        <Typography><i>E-mail::</i> <b>{data?.email}</b></Typography>
                        <Typography><i>Pachet:</i> <b>{data?.package}</b></Typography>
                        <Typography><i>Domeniu:</i> <b>{data?.domain} {data?.domainOp} RON</b></Typography>
                        <Typography><i>Business Email:</i> <b>{data?.businessEmail}</b></Typography>
                        <Typography><i>Mesaj:</i> <b>{data?.message}</b></Typography>
                        <Buttons>
                            <Button variant="outlined" size="small" onClick={() => handleDelivered(id, data?.read)}>
                                {data?.read ? 'Marchează ca nelivrat' : 'Marchează ca livrat'}
                            </Button>
                            <Button variant="contained" color="secondary" disableElevation={true} onClick={() => handleDelete(id)} size="small">
                                Șterge
                            </Button>
                        </Buttons>
                    </AccordionDetails>
                </MyAccordion>
            ))}
        </Container>
    )
})

export default SoldProducts


const Container = styled.div`
    width: 1000px;
    max-width: 96vw;
    margin: 100px auto 0;
`
const Title = styled.h2`
    font-weight: 400;
    margin: 20px 0;
`
const MyAccordion = styled(Accordion)`
    &.marked {
        background-color: grey;
    }
`
const MyTypography = styled(Typography)`
    flex-basis: 50%;
    flex-shrink: 0;
    &.marked {
        color: lightgray;
        text-decoration: line-through;
    }
`
const PriceTypography = styled(Typography)`
    text-align: right;
    width: 100%;
    >b{
        color: var(--c1);
    }
    &.marked {
        color: lightgray;
        text-decoration: line-through;
    }
`
const Buttons = styled.div`
    align-self: flex-end;
    >button {
        margin-left: 10px;
    }
`