import { Avatar } from '@material-ui/core';
import { motion } from 'framer-motion'
import React from 'react'
import { NavLink } from 'react-router-dom';
import styled from 'styled-components'


const variants = {
    open: custom => ({
        opacity: 1,
        y: 0,
        transition: {
            delay: custom * 0.1,
        },
        }),
        closed: { 
            opacity: 0,
            y: 50,
            transition: {
                duration:  0.2,
            }
        },
    }

    const wrapper = {
        open: {
            transition: {
                staggerChildren: 0.07, delayChildren: 0.4
            }
        },
        closed: {
            transition: {
                staggerChildren: 0.10, staggerDirection: -1,
            }
        }
    }
export default function Sidebar({user, owner, handleLogout, toggle, isOpen}) {

    return (
        <Ol as={motion.ol} variants={wrapper} >
            <Li 
            isOpen={isOpen}
            key={1}
            as={motion.li}
            custom={1}
            variants={variants}
            whileHover={{ scale: 1.5 }}
            whileTap={{ scale: 0.90 }}
            >
                <MyAvatar src={user?.photoUrl} alt="user image" />
            </Li>
            <Li 
            isOpen={isOpen}
            key={2}
            as={motion.li}
            custom={2}
            variants={variants}
            whileHover={{ scale: 1.5 }}
            whileTap={{ scale: 0.90 }}
            >
                <MyNavLink onClick={() => {window.scrollTo(0, 0); toggle()}} activeClassName="active" exact={true}  to="">
                    acasă
                </MyNavLink>
            </Li>
            <Li 
            isOpen={isOpen}
            key={3}
            as={motion.li}
            custom={3}
            variants={variants}
            whileHover={{ scale: 1.5 }}
            whileTap={{ scale: 0.90 }}
            >
                {owner ?
                    <MyNavLink onClick={() => {window.scrollTo(0, 0); toggle()}} activeClassName="active" exact={true} to="admin">
                        admin
                    </MyNavLink>
                    :
                    <MyNavLink onClick={() => {window.scrollTo(0, 0); toggle()}} activeClassName="active" exact={true} to="cumpara">
                        cumpără
                    </MyNavLink>
                }
            </Li>
            <Li 
            isOpen={isOpen}
            key={4}
            as={motion.li}
            custom={4}
            variants={variants}
            whileHover={{ scale: 1.5 }}
            whileTap={{ scale: 0.90 }}
            >
                {!user ?
                    <MyNavLink onClick={() => {window.scrollTo(0, 0); toggle()}} activeClassName="active" exact={true} to="login">
                        login
                    </MyNavLink>
                    :
                    <MyNavLink onClick={() => {handleLogout(); toggle()}} activeClassName="active" exact={true} to="login">
                        logout
                    </MyNavLink>
                }
            </Li>
        </Ol>
    )
}


const Ol = styled.ol`
    position: fixed;
    top: 0;
    width: 100%;
    height: 100vh;
    left: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    z-index: 50;
    pointer-events: none;
    overflow: hidden;
`
const Li = styled.li`
    list-style: none;
    margin: 20px;
    display: flex;
    align-items: center;
    cursor: pointer;
    pointer-events: ${({isOpen}) => isOpen ? 'all' : 'none'};
`
const MyNavLink = styled(NavLink)`
    font-size: var(--mf);
    color: black;
    text-decoration: none;
    line-height: 2;
    &:hover {
        color: white;
    }
    &.active {
        color: var(--crl);
        &:hover {
            color: white;
        }
    }
`
const MyAvatar = styled(Avatar)`
    border: 1px solid var(--cbl);
    width: 70px !important;
    height: 70px !important;
    margin-bottom: 30px;
`