import { Button } from '@material-ui/core'
import React from 'react'
import styled from 'styled-components'

export default function ReviewTab({value, index, data, id, handleDelete, handleRead}) {
    return (
        <Container
        role="tabpanel"
        hidden={value !== index}
        id={`full-width-tabpanel-${index}`}
        aria-labelledby={`full-width-tab-${index}`}
        >
        {value === index && (
            <Wrapper className={data.read? 'seen' : '' }>
                <Heading><b>{data?.name}</b> pe data: <i>{new Date(data?.timestamp?.toDate()).toLocaleString('ro')}</i></Heading>
                <Text>Email: <i>{data?.email}</i></Text>
                <Message>Mesaj: "{data?.message}"</Message>
                <Text>Rating: <i>{data?.rating}</i></Text>
                <Text>Public: <i>{data?.public ? 'Public' : 'Privat'}</i></Text>

                <Buttons>
                    <Button className={data.read ? 'seen' : ''} variant="outlined" size="small" onClick={() => handleRead(id, data.read)}>
                            {data.read ? 'Marchează ca necitit' : 'Marchează ca citit'}
                    </Button>
                    <Button variant="contained" color="secondary" disableElevation={true} onClick={() => handleDelete(id)} size="small">
                        Șterge
                    </Button>
                </Buttons>
            </Wrapper>
        )}
        </Container>
    )
}



const Container = styled.aside`
    padding-top: 10px;
`
const Wrapper = styled.div`
    padding: 10px 5px;
    &.seen {
        color: lightgray;
    }
`
const Heading = styled.p`
    margin-bottom: 30px;
`
const Text = styled.p`

`
const Message = styled.p`
    margin-top: 20px;
`
const Buttons = styled.div`
    display: flex;
    justify-content: flex-end;
    >button {
        margin-left: 10px;
        &.seen {
        background-color: grey;
        }
    }
    
`